using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");

var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var search = new WebSearchTool();
var notes  = new NoteTakingTool();

List<AITool> tools =
[
    AIFunctionFactory.Create(search.SearchWeb),
    AIFunctionFactory.Create(notes.SaveNote),
    AIFunctionFactory.Create(notes.GetNotes),
];

// ---------------------------------------------------------------------------
// Chat client (no automatic function invocation – we loop manually so we can
// log each tool call to the console)
// ---------------------------------------------------------------------------
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient();

// ---------------------------------------------------------------------------
// Prompt
// ---------------------------------------------------------------------------
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a thorough research agent. Follow this process:
        1. Search the web with at least 3 different queries to gather broad information.
        2. After each search, save the key findings as notes with SaveNote.
        3. When you have gathered enough material, call GetNotes to review everything.
        4. Produce a comprehensive, well-structured summary with clear sections.
        Be specific and cite sources where possible.
        """),
    new(ChatRole.User,
        $"Research the following topic and provide a detailed summary: {topic}"),
];

var options = new ChatOptions { Tools = tools };

// ---------------------------------------------------------------------------
// Agent loop
// ---------------------------------------------------------------------------
const int maxIterations = 20;

for (int i = 0; i < maxIterations; i++)
{
    var response = await client.GetResponseAsync(messages, options);

    // Append every response message to the conversation history.
    foreach (var msg in response.Messages)
        messages.Add(msg);

    // Collect tool / function calls from the response.
    var functionCalls = response.Messages
        .SelectMany(m => m.Contents.OfType<FunctionCallContent>())
        .ToList();

    if (functionCalls.Count == 0)
    {
        // No tool calls – the agent is done.
        Console.WriteLine("\n========== RESEARCH SUMMARY ==========\n");
        Console.WriteLine(response.Text);
        break;
    }

    // Execute each requested tool call.
    foreach (var call in functionCalls)
    {
        var argsSummary = call.Arguments is { Count: > 0 }
            ? string.Join(", ", call.Arguments.Select(kv =>
                $"{kv.Key}: \"{Truncate(kv.Value?.ToString(), 60)}\""))
            : "";
        Console.WriteLine($"  🔧 {call.Name}({argsSummary})");

        var aiFunction = tools.OfType<AIFunction>()
            .FirstOrDefault(f => f.Name == call.Name);

        object? result = aiFunction is not null
            ? await aiFunction.InvokeAsync(call.Arguments)
            : "Unknown tool.";

        messages.Add(new ChatMessage(ChatRole.Tool,
            [new FunctionResultContent(call.CallId, call.Name, result)]));
    }
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------
static string Truncate(string? value, int maxLen) =>
    value is null ? "" : value.Length <= maxLen ? value : value[..maxLen] + "…";

// ===================================================================
// Web-search tool – uses DuckDuckGo HTML endpoint (no API key needed)
// ===================================================================
sealed class WebSearchTool
{
    private readonly HttpClient _http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0 (compatible)" },
        },
    };

    [Description("Search the web for information. Returns the top results with titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={WebUtility.UrlEncode(query)}";
            var html = await _http.GetStringAsync(url);

            var results = ParseResults(html);
            if (results.Count == 0)
                return "No results found.";

            var sb = new StringBuilder();
            foreach (var (title, snippet, link, idx) in
                     results.Take(5).Select((r, i) => (r.Title, r.Snippet, r.Url, i + 1)))
            {
                sb.AppendLine($"[{idx}] {title}");
                if (!string.IsNullOrWhiteSpace(snippet))
                    sb.AppendLine($"    {snippet}");
                if (!string.IsNullOrWhiteSpace(link))
                    sb.AppendLine($"    URL: {link}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    // Lightweight HTML scraping – good enough for DuckDuckGo's HTML results page.
    private static List<(string Title, string Snippet, string Url)> ParseResults(string html)
    {
        var results = new List<(string, string, string)>();
        var blocks = html.Split("class=\"result__body\"",
            StringSplitOptions.RemoveEmptyEntries);

        for (int i = 1; i < blocks.Length && results.Count < 5; i++)
        {
            var block = blocks[i];
            var title   = CleanField(block, "class=\"result__a\"",       "</a>");
            var snippet = CleanField(block, "class=\"result__snippet\"", "</a>")
                       ?? CleanField(block, "class=\"result__snippet\"", "</span>");
            var link    = CleanField(block, "class=\"result__url\"",     "</a>");

            if (!string.IsNullOrWhiteSpace(title))
                results.Add((title, snippet ?? "", link ?? ""));
        }

        return results;
    }

    private static string? CleanField(string block, string startMarker, string endMarker)
    {
        var start = block.IndexOf(startMarker, StringComparison.Ordinal);
        if (start < 0) return null;
        var end = block.IndexOf(endMarker, start, StringComparison.Ordinal);
        if (end < 0) return null;

        var raw = block[start..end];
        // Skip past the closing '>' of the opening tag.
        var gt = raw.IndexOf('>');
        if (gt >= 0) raw = raw[(gt + 1)..];

        return StripHtml(raw).Trim();
    }

    private static string StripHtml(string html)
    {
        var sb = new StringBuilder(html.Length);
        bool inside = false;
        foreach (var ch in html)
        {
            if (ch == '<') { inside = true; continue; }
            if (ch == '>') { inside = false; continue; }
            if (!inside) sb.Append(ch);
        }
        return WebUtility.HtmlDecode(sb.ToString());
    }
}

// ===================================================================
// Note-taking tool – in-memory research notebook
// ===================================================================
sealed class NoteTakingTool
{
    private readonly List<(string Topic, string Content)> _notes = [];

    [Description("Save a research note. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("Short topic label")] string topic,
        [Description("The note content")]   string content)
    {
        _notes.Add((topic, content));
        return $"Note saved under \"{topic}\". Total notes: {_notes.Count}";
    }

    [Description("Retrieve all saved research notes so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {_notes[i].Topic} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

