1. using System.ComponentModel;
2. using System.Net;
3. using System.Text;
4. using System.Text.Json;
5. using Microsoft.Extensions.AI;
6. using OpenAI;
7. 
8. // ---------------------------------------------------------------------------
9. // Configuration
10. // ---------------------------------------------------------------------------
11. var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
12.     ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
13. 
14. var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
15. 
16. // ---------------------------------------------------------------------------
17. // Tools
18. // ---------------------------------------------------------------------------
19. var search = new WebSearchTool();
20. var notes  = new NoteTakingTool();
21. 
22. List<AITool> tools =
23. [
24.     AIFunctionFactory.Create(search.SearchWeb),
25.     AIFunctionFactory.Create(notes.SaveNote),
26.     AIFunctionFactory.Create(notes.GetNotes),
27. ];
28. 
29. // ---------------------------------------------------------------------------
30. // Chat client (no automatic function invocation – we loop manually so we can
31. // log each tool call to the console)
32. // ---------------------------------------------------------------------------
33. IChatClient client = new OpenAIClient(apiKey)
34.     .GetChatClient(modelName)
35.     .AsIChatClient();
36. 
37. // ---------------------------------------------------------------------------
38. // Prompt
39. // ---------------------------------------------------------------------------
40. Console.Write("Enter a research topic: ");
41. var topic = Console.ReadLine()?.Trim();
42. if (string.IsNullOrEmpty(topic))
43. {
44.     Console.WriteLine("No topic provided.");
45.     return;
46. }
47. 
48. Console.WriteLine($"\n🔍 Researching: {topic}\n");
49. 
50. List<ChatMessage> messages =
51. [
52.     new(ChatRole.System, """
53.         You are a thorough research agent. Follow this process:
54.         1. Search the web with at least 3 different queries to gather broad information.
55.         2. After each search, save the key findings as notes with SaveNote.
56.         3. When you have gathered enough material, call GetNotes to review everything.
57.         4. Produce a comprehensive, well-structured summary with clear sections.
58.         Be specific and cite sources where possible.
59.         """),
60.     new(ChatRole.User,
61.         $"Research the following topic and provide a detailed summary: {topic}"),
62. ];
63. 
64. var options = new ChatOptions { Tools = tools };
65. 
66. // ---------------------------------------------------------------------------
67. // Agent loop
68. // ---------------------------------------------------------------------------
69. const int maxIterations = 20;
70. 
71. for (int i = 0; i < maxIterations; i++)
72. {
73.     var response = await client.GetResponseAsync(messages, options);
74. 
75.     // Append every response message to the conversation history.
76.     foreach (var msg in response.Messages)
77.         messages.Add(msg);
78. 
79.     // Collect tool / function calls from the response.
80.     var functionCalls = response.Messages
81.         .SelectMany(m => m.Contents.OfType<FunctionCallContent>())
82.         .ToList();
83. 
84.     if (functionCalls.Count == 0)
85.     {
86.         // No tool calls – the agent is done.
87.         Console.WriteLine("\n========== RESEARCH SUMMARY ==========\n");
88.         Console.WriteLine(response.Text);
89.         break;
90.     }
91. 
92.     // Execute each requested tool call.
93.     foreach (var call in functionCalls)
94.     {
95.         var argsSummary = call.Arguments is { Count: > 0 }
96.             ? string.Join(", ", call.Arguments.Select(kv =>
97.                 $"{kv.Key}: \"{Truncate(kv.Value?.ToString(), 60)}\""))
98.             : "";
99.         Console.WriteLine($"  🔧 {call.Name}({argsSummary})");
100. 
101.         var aiFunction = tools.OfType<AIFunction>()
102.             .FirstOrDefault(f => f.Name == call.Name);
103. 
104.         object? result = aiFunction is not null
105.             ? await aiFunction.InvokeAsync(
106.                   call.Arguments is not null ? new AIFunctionArguments(call.Arguments) : null)
107.             : "Unknown tool.";
108. 
109.         messages.Add(new ChatMessage(ChatRole.Tool,
110.             [new FunctionResultContent(call.CallId, result)]));
111.     }
112. }
113. 
114. // ---------------------------------------------------------------------------
115. // Helpers
116. // ---------------------------------------------------------------------------
117. static string Truncate(string? value, int maxLen) =>
118.     value is null ? "" : value.Length <= maxLen ? value : value[..maxLen] + "…";
119. 
120. // ===================================================================
121. // Web-search tool – uses DuckDuckGo HTML endpoint (no API key needed)
122. // ===================================================================
123. sealed class WebSearchTool
124. {
125.     private readonly HttpClient _http = new()
126.     {
127.         DefaultRequestHeaders =
128.         {
129.             { "User-Agent", "ResearchAgent/1.0 (compatible)" },
130.         },
131.     };
132. 
133.     [Description("Search the web for information. Returns the top results with titles, snippets, and URLs.")]
134.     public async Task<string> SearchWeb(
135.         [Description("The search query")] string query)
136.     {
137.         try
138.         {
139.             var url = $"https://html.duckduckgo.com/html/?q={WebUtility.UrlEncode(query)}";
140.             var html = await _http.GetStringAsync(url);
141. 
142.             var results = ParseResults(html);
143.             if (results.Count == 0)
144.                 return "No results found.";
145. 
146.             var sb = new StringBuilder();
147.             foreach (var (title, snippet, link, idx) in
148.                      results.Take(5).Select((r, i) => (r.Title, r.Snippet, r.Url, i + 1)))
149.             {
150.                 sb.AppendLine($"[{idx}] {title}");
151.                 if (!string.IsNullOrWhiteSpace(snippet))
152.                     sb.AppendLine($"    {snippet}");
153.                 if (!string.IsNullOrWhiteSpace(link))
154.                     sb.AppendLine($"    URL: {link}");
155.                 sb.AppendLine();
156.             }
157. 
158.             return sb.ToString();
159.         }
160.         catch (Exception ex)
161.         {
162.             return $"Search failed: {ex.Message}";
163.         }
164.     }
165. 
166.     // Lightweight HTML scraping – good enough for DuckDuckGo's HTML results page.
167.     private static List<(string Title, string Snippet, string Url)> ParseResults(string html)
168.     {
169.         var results = new List<(string, string, string)>();
170.         var blocks = html.Split("class=\"result__body\"",
171.             StringSplitOptions.RemoveEmptyEntries);
172. 
173.         for (int i = 1; i < blocks.Length && results.Count < 5; i++)
174.         {
175.             var block = blocks[i];
176.             var title   = CleanField(block, "class=\"result__a\"",       "</a>");
177.             var snippet = CleanField(block, "class=\"result__snippet\"", "</a>")
178.                        ?? CleanField(block, "class=\"result__snippet\"", "</span>");
179.             var link    = CleanField(block, "class=\"result__url\"",     "</a>");
180. 
181.             if (!string.IsNullOrWhiteSpace(title))
182.                 results.Add((title, snippet ?? "", link ?? ""));
183.         }
184. 
185.         return results;
186.     }
187. 
