 using System.ComponentModel;
 using System.Net;
 using System.Text;
 using System.Text.Json;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // ---------------------------------------------------------------------------
 // Configuration
 // ---------------------------------------------------------------------------
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");

 var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

 // ---------------------------------------------------------------------------
 // Tools
 // ---------------------------------------------------------------------------
 var search = new WebSearchTool();
 var notes  = new NoteTakingTool();

 List<AITool> tools =
 [
     AIFunctionFactory.Create(search.SearchWeb),
     AIFunctionFactory.Create(notes.SaveNote),
     AIFunctionFactory.Create(notes.GetNotes),
 ];

 // ---------------------------------------------------------------------------
 // Chat client (no automatic function invocation – we loop manually so we can
 // log each tool call to the console)
 // ---------------------------------------------------------------------------
 IChatClient client = new OpenAIClient(apiKey)
     .GetChatClient(modelName)
     .AsIChatClient();

 // ---------------------------------------------------------------------------
 // Prompt
 // ---------------------------------------------------------------------------
 Console.Write("Enter a research topic: ");
 var topic = Console.ReadLine()?.Trim();
 if (string.IsNullOrEmpty(topic))
 {
     Console.WriteLine("No topic provided.");
     return;
 }

 Console.WriteLine($"\n🔍 Researching: {topic}\n");

 List<ChatMessage> messages =
 [
     new(ChatRole.System, """
         You are a thorough research agent. Follow this process:
         1. Search the web with at least 3 different queries to gather broad information.
         2. After each search, save the key findings as notes with SaveNote.
         3. When you have gathered enough material, call GetNotes to review everything.
         4. Produce a comprehensive, well-structured summary with clear sections.
         Be specific and cite sources where possible.
         """),
     new(ChatRole.User,
         $"Research the following topic and provide a detailed summary: {topic}"),
 ];

 var options = new ChatOptions { Tools = tools };

 // ---------------------------------------------------------------------------
 // Agent loop
 // ---------------------------------------------------------------------------
 const int maxIterations = 20;

 for (int i = 0; i < maxIterations; i++)
 {
     var response = await client.GetResponseAsync(messages, options);

     // Append every response message to the conversation history.
     foreach (var msg in response.Messages)
         messages.Add(msg);

     // Collect tool / function calls from the response.
     var functionCalls = response.Messages
         .SelectMany(m => m.Contents.OfType<FunctionCallContent>())
         .ToList();

     if (functionCalls.Count == 0)
     {
         // No tool calls – the agent is done.
         Console.WriteLine("\n========== RESEARCH SUMMARY ==========\n");
         Console.WriteLine(response.Text);
         break;
     }

     // Execute each requested tool call.
     foreach (var call in functionCalls)
     {
         var argsSummary = call.Arguments is { Count: > 0 }
             ? string.Join(", ", call.Arguments.Select(kv =>
                 $"{kv.Key}: \"{Truncate(kv.Value?.ToString(), 60)}\""))
             : "";
         Console.WriteLine($"  🔧 {call.Name}({argsSummary})");

         var aiFunction = tools.OfType<AIFunction>()
             .FirstOrDefault(f => f.Name == call.Name);

         object? result = aiFunction is not null
             ? await aiFunction.InvokeAsync(
                   call.Arguments is not null ? new AIFunctionArguments(call.Arguments) : null)
             : "Unknown tool.";

         messages.Add(new ChatMessage(ChatRole.Tool,
             [new FunctionResultContent(call.CallId, result)]));
     }
 }

