 static string Truncate(string? value, int maxLen) =>
     value is null ? "" : value.Length <= maxLen ? value : value[..maxLen] + "…";

 // ===================================================================
 // Web-search tool – uses DuckDuckGo HTML endpoint (no API key needed)
 // ===================================================================
 sealed class WebSearchTool
 {
     private readonly HttpClient _http = new()
     {
         DefaultRequestHeaders =
         {
             { "User-Agent", "ResearchAgent/1.0 (compatible)" },
         },
     };

     [Description("Search the web for information. Returns the top results with titles, snippets, and URLs.")]
     public async Task<string> SearchWeb(
         [Description("The search query")] string query)
     {
         try
         {
             var url = $"https://html.duckduckgo.com/html/?q={WebUtility.UrlEncode(query)}";
             var html = await _http.GetStringAsync(url);

             var results = ParseResults(html);
             if (results.Count == 0)
                 return "No results found.";

             var sb = new StringBuilder();
             foreach (var (title, snippet, link, idx) in
                      results.Take(5).Select((r, i) => (r.Title, r.Snippet, r.Url, i + 1)))
             {
                 sb.AppendLine($"[{idx}] {title}");
                 if (!string.IsNullOrWhiteSpace(snippet))
                     sb.AppendLine($"    {snippet}");
                 if (!string.IsNullOrWhiteSpace(link))
                     sb.AppendLine($"    URL: {link}");
                 sb.AppendLine();
             }

             return sb.ToString();
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}";
         }
     }

     // Lightweight HTML scraping – good enough for DuckDuckGo's HTML results page.
     private static List<(string Title, string Snippet, string Url)> ParseResults(string html)
     {
         var results = new List<(string, string, string)>();
         var blocks = html.Split("class=\"result__body\"",
             StringSplitOptions.RemoveEmptyEntries);

         for (int i = 1; i < blocks.Length && results.Count < 5; i++)
         {
             var block = blocks[i];
             var title   = CleanField(block, "class=\"result__a\"",       "</a>");
             var snippet = CleanField(block, "class=\"result__snippet\"", "</a>")
                        ?? CleanField(block, "class=\"result__snippet\"", "</span>");
             var link    = CleanField(block, "class=\"result__url\"",     "</a>");

             if (!string.IsNullOrWhiteSpace(title))
                 results.Add((title, snippet ?? "", link ?? ""));
         }

         return results;
     }

     private static string? CleanField(string block, string startMarker, string endMarker)
     {
         var start = block.IndexOf(startMarker, StringComparison.Ordinal);
         if (start < 0) return null;
         var end = block.IndexOf(endMarker, start, StringComparison.Ordinal);
         if (end < 0) return null;

         var raw = block[start..end];
         // Skip past the closing '>' of the opening tag.
         var gt = raw.IndexOf('>');
         if (gt >= 0) raw = raw[(gt + 1)..];

         return StripHtml(raw).Trim();
     }

     private static string StripHtml(string html)
     {
         var sb = new StringBuilder(html.Length);
         bool inside = false;
         foreach (var ch in html)
         {
             if (ch == '<') { inside = true; continue; }
             if (ch == '>') { inside = false; continue; }
             if (!inside) sb.Append(ch);
         }
         return WebUtility.HtmlDecode(sb.ToString());
     }
 }

